header.content:
@media all {
  *,
  div,
  span {
    font-family: Arboria !important;
  }
  a:focus,
  a:hover {
    outline: 1px solid transparent;
  }
}

.typography-root {
  margin: 0;
}

.typography-colorPrimary {
  color: #000;
}

.icon-root {
  fill: currentColor;
  width: 1em;
  height: 1em;
  display: inline-block;
  font-size: 1.5rem;
  transition: fill 200ms cubic-bezier(0.4, 0, 0.2, 1) 0ms;
  flex-shrink: 0;
  user-select: none;
}

.link-underlineHover {
  text-decoration: none;
}

.link-underlineHover:hover {
  text-decoration: underline;
}

.link-button {
  border: 0;
  cursor: pointer;
  margin: 0;
  outline: 0;
  padding: 0;
  position: relative;
  user-select: none;
  border-radius: 0;
  vertical-align: middle;
  appearance: none;
  background-color: transparent;
  -webkit-tap-highlight-color: transparent;
}

.nav-sites {
  width: 100%;
  height: 44px;
  margin: 0;
  display: flex;
  overflow: auto;
  align-items: center;
}

.nav-sites__item {
  border: solid transparent 3px;
  height: 100%;
  display: inline;
}

.nav-sites__item:hover {
/*  background-color: #424242;*/
  background-color: #144746 !important;
}

.nav-sites__item:first-child {
  background-color: #ffffff;
}

.nav-sites__item:first-child:hover {
  background-color: #fff !important;
}

.nav-sites__link {
  height: 100%;
  display: flex;
  padding: 0 16px;
  align-items: center;
  justify-content: center;
}

.nav-services {
  height: 100%;
  margin: 0;
  display: flex;
  overflow: auto;
  align-items: center;
  justify-content: space-between;
}

.nav-services__item {
  border: solid transparent 3px;
}

.nav-services__item:first-child {
  margin-right: 16px;
}

.nav-services__item:nth-child(2) {
  margin-right: 16px;
}

.nav-services__link {
  color: #212121;
  display: flex;
  flex-wrap: nowrap;
  align-items: center;
}

.nav-services__link:hover {
  text-decoration: underline;
}

.nav-services__text {
  margin: 0;
  font-size: 14px;
  white-space: nowrap;
  padding-left: 8px;
}

.geolocation {
  display: flex;
  padding: 8px;
  align-items: center;
  white-space: nowrap;
}

.geolocation__button {
  display: flex;
  font-size: 10px;
  text-align: right;
  align-items: center;
  line-height: 1;
}

.geolocation__button svg {
  color: #212121;
  font-size: 24px;
}

.geolocation__text {
  color: #212121;
  margin: 0 2px;
  font-weight: 300;
  letter-spacing: 0.25px;
}

.geolocation__text span {
  display: block;
}

.header-top {
  height: 44px;
  overflow: auto;
/*  background-color: #212121;*/
  background-color: #0c2e2d;
}

.header-top__container {
  width: 100%;
  height: 100%;
  margin: 0 auto;
  display: flex;
  padding: 0 24px;
  max-width: 1280px;
  justify-content: space-between;
}

.header-top__nav {
  margin-left: 40px;
}

.header-top__nav p {
  font-size: 13px;
}

.header-top__nav * {
  color: #ffffff;
}

.header-bottom {
  height: 44px;
  background-color: #ffffff;
}

@media (max-width: 1279.95px) {
  .geolocation {
    padding: 4px 0px;
    flex-grow: 2;
    white-space: unset;
  }
  .geolocation__button {
    text-align: left;
    flex-direction: row-reverse;
  }
}

@media (max-width: 959.95px) {
  .geolocation__button svg {
    font-size: 16px;
  }
}

@media (min-width: 600px) {
  #nav-sites__item-cartao {
    display: none
  }
}

@media (max-width: 599.95px) {
  .header-top__container {
    padding: 0;
  }
  .header-bottom {
    display: none;
  }
  #nav-sites__item-blog {
    display: none;
  }
}

