@media (max-width: 1279px) {
  .base__subtitle {
    text-align: center;
  }
  .base__icon__box {
    padding: 0px 7.5px;
    flex-grow: 0;
  }
  .apps__container {
    max-width: 350px;
  }
  .apps__list {
    justify-content: center;
  }
  .content__list {
    justify-content: center;
  }
  .navigation__title {
    border-top: 2px solid #D7D0BB;
    padding-bottom: 16px;
  }
  .accordion {
    flex-direction: column;
/*    background-color: #f6f6f6;*/
    background-color: #0C2E2D;
    margin: 0;
  }
  .accordion__header {
    cursor: pointer;
    display: flex;
  }
  .accordion__header > h3 {
    flex-grow: 1;
    text-align: left;
    padding-left: 40px;
    padding-right: 40px;
    font-size: 16px;
  }
  .accordion__header::after {
    position: absolute;
    content: "+";
    color: #D7D0BB;
    flex-grow: 0;
    font-size: 1.5rem;
    right: 8px;
    line-height: 1.25;
    padding: 12px 30px 12px 12px;
  }
  .accordion__content {
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    padding-bottom: 16px;
    padding-left: 40px;
  }
  .accordion__header + .accordion__content {
    display: none;
  }
  .accordion__header.is-open + .accordion__content {
    display: flex;
  }
  .accordion__header.is-open::after {
    position: absolute;
    content: "-";
    flex-grow: 0;
    font-size: 1.5rem;
    right: 8px;
    line-height: 1.25;
    padding: 12px 30px 0 12px;
  }
  .navigation__item {
    font-weight: 300;
    line-height: 1.5;
  }
  .navigation__item:first-child {
