  }
  .copyright__button {
    max-width: 75px;
    border: none;
    background: none;
    text-decoration: underline;
    margin: 0;
    padding: 0;
    cursor: pointer;
    color: #fff;
    font-weight: lighter;
  }
}

const accordionItems = document.querySelectorAll(".accordion__header");

accordionItems.forEach((accordionItem) => {
  if (window.screen.width < 1280) {
    accordionItem.setAttribute("role", "button");
  }

  accordionItem.addEventListener("click", () => {
    accordionItem.classList.toggle("is-open");
  });
});

const content = document.getElementById("copyright__content");
const btn = document.getElementById("copyright__btn");

btn.addEventListener("click", () => {
  if (content.classList.contains("show")) {
    content.classList.remove("show");
    btn.textContent = "Ler mais";
  } else {
    content.classList.add("show");
    btn.textContent = "Ler menos";
  }
});
